    // --- Helper functions ---

    /** Shorthand for Availability */
    

    private fun tes(
        number: String,
        address: String,
        region: Region,
        lat: Double,
        lng: Double,
        ai92: Availability = Availability.NOT_AVAILABLE,
        ai92p: Availability = Availability.NOT_AVAILABLE,
        ai95: Availability = Availability.NOT_AVAILABLE,
        ai95p: Availability = Availability.NOT_AVAILABLE,
        ai100: Availability = Availability.NOT_AVAILABLE,
        dt: Availability = Availability.NOT_AVAILABLE,
        dtp: Availability = Availability.NOT_AVAILABLE,
        lpg: Availability = Availability.NOT_AVAILABLE,
        methane: Availability = Availability.NOT_AVAILABLE
    ): Station {
        val fuelStatuses = listOf(
            FuelStatus(FuelType.AI_92, ai92),
            FuelStatus(FuelType.AI_95, ai95),
            FuelStatus(FuelType.AI_95_PLUS, ai95p),
            FuelStatus(FuelType.AI_100, ai100),
            FuelStatus(FuelType.DT, dt),
            FuelStatus(FuelType.DT_PLUS, dtp),
            FuelStatus(FuelType.GAS, if (lpg != Availability.NOT_AVAILABLE) lpg else methane)
        )

        // Determine payment methods based on availability
        val paymentMethods = mutableListOf<PaymentMethod>()
        if (fuelStatuses.any { it.availability == Availability.CARDS_ONLY }) {
            paymentMethods.add(PaymentMethod.CARDS)
        }
        if (fuelStatuses.any { it.availability == Availability.FREE_SALE }) {
            paymentMethods.add(PaymentMethod.CASH)
            paymentMethods.add(PaymentMethod.CASHLESS)
        }
        if (paymentMethods.isEmpty()) {
            paymentMethods.addAll(PaymentMethod.entries)
        }

        return Station(
            id = "tes_$number",
            number = number,
            network = "ТЭС",
            address = address,
            region = region,
            latitude = lat,
            longitude = lng,
            fuelStatuses = fuelStatuses,
            paymentMethods = paymentMethods,
            lastUpdated = 1748764800000L, // 2026-06-01 approx
            lastUpdatedBy = "system",
            comment = null,
            isVerified = true
        )
    }

    private fun other(
        id: String,
        network: String,
        number: String,
        address: String,
        region: Region,
        lat: Double,
        lng: Double
    ): Station {
        val fuelStatuses = FuelType.entries.map { fuelType ->
            FuelStatus(fuelType, Availability.UNKNOWN)
        }

        return Station(
            id = id,
            number = number,
            network = network,
            address = address,
            region = region,
            latitude = lat,
            longitude = lng,
            fuelStatuses = fuelStatuses,
            paymentMethods = PaymentMethod.entries.toList(),
            lastUpdated = 0L,
            lastUpdatedBy = null,
            comment = null,
            isVerified = false
        )
    }
}
